     1→/**
     2→ * ProjectTree Component
     3→ *
     4→ * Hierarchical tree view for displaying and selecting projects.
     5→ * Supports expand/collapse, selection (single or multi), and inline actions.
     6→ *
     7→ * Used by:
     8→ * - ProjectContextDropdown (global filter)
     9→ * - ProjectPicker (entity assignment)
    10→ * - Settings > Projects management
    11→ */
    12→
    13→import React, { useState, useCallback } from 'react';
    14→import { ChevronRight, ChevronDown, Folder, FolderOpen } from 'lucide-react';
    15→import { useProjectContextStore } from '../stores/useProjectContextStore';
    16→import type { ProjectContext } from '../types';
    17→
    18→// ============================================================================
    19→// Types
    20→// ============================================================================
    21→
    22→interface ProjectTreeProps {
    23→  /** Selection mode: single project, multiple, or none (display only) */
    24→  selectionMode?: 'single' | 'multi' | 'none';
    25→  /** Currently selected project IDs */
    26→  selectedIds?: string[];
    27→  /** Callback when selection changes */
    28→  onSelectionChange?: (ids: string[]) => void;
    29→  /** Callback when project is clicked (for navigation/details) */
    30→  onProjectClick?: (project: ProjectContext) => void;
    31→  /** Show archived projects */
    32→  showArchived?: boolean;
    33→  /** Show "All Projects" option at top */
    34→  showAllOption?: boolean;
    35→  /** Whether "All Projects" is currently selected */
    36→  allSelected?: boolean;
    37→  /** Callback when "All" is selected */
    38→  onSelectAll?: () => void;
    39→  /** Custom class for the container */
    40→  className?: string;
    41→  /** Compact mode for dropdowns */
    42→  compact?: boolean;
    43→}
    44→
    45→interface ProjectNodeProps {
    46→  project: ProjectContext;
    47→  level: number;
    48→  expanded: boolean;
    49→  onToggleExpand: (id: string) => void;
    50→  selectionMode: 'single' | 'multi' | 'none';
    51→  isSelected: boolean;
    52→  onSelect: (project: ProjectContext) => void;
    53→  onProjectClick?: (project: ProjectContext) => void;
    54→  childProjects: ProjectContext[];
    55→  compact?: boolean;
    56→}
    57→
    58→// ============================================================================
    59→// ProjectNode Component (recursive)
    60→// ============================================================================
    61→
    62→const ProjectNode: React.FC<ProjectNodeProps> = ({
    63→  project,
    64→  level,
    65→  expanded,
    66→  onToggleExpand,
    67→  selectionMode,
    68→  isSelected,
    69→  onSelect,
    70→  onProjectClick,
    71→  childProjects,
    72→  compact,
    73→}) => {
    74→  const hasChildren = childProjects.length > 0;
    75→  const paddingLeft = level * (compact ? 12 : 16);
    76→
    77→  const handleClick = (e: React.MouseEvent) => {
    78→    e.stopPropagation();
    79→    if (selectionMode !== 'none') {
    80→      onSelect(project);
    81→    } else if (onProjectClick) {
    82→      onProjectClick(project);
    83→    }
    84→  };
    85→
    86→  const handleExpandClick = (e: React.MouseEvent) => {
    87→    e.stopPropagation();
    88→    onToggleExpand(project.id);
    89→  };
    90→
    91→  return (
    92→    <div>
    93→      <button
    94→        type="button"
    95→        onClick={handleClick}
    96→        className={`
    97→          w-full flex items-center gap-2 text-left transition-colors
    98→          ${compact ? 'px-2 py-1.5 text-sm' : 'px-3 py-2'}
    99→          ${isSelected
   100→            ? 'bg-accent-blue/10 text-accent-blue dark:bg-accent-blue/20'
   101→            : 'hover:bg-surface-light-elevated dark:hover:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary'
   102→          }
   103→        `}
   104→        style={{ paddingLeft: `${paddingLeft + (compact ? 8 : 12)}px` }}
   105→      >
   106→        {/* Expand/collapse button or spacer */}
   107→        {hasChildren ? (
   108→          <button
   109→            type="button"
   110→            onClick={handleExpandClick}
   111→            className="p-0.5 hover:bg-neutral-200 dark:hover:bg-neutral-700 rounded transition-colors"
   112→            aria-label={expanded ? 'Collapse' : 'Expand'}
   113→          >
   114→            {expanded ? (
   115→              <ChevronDown className={compact ? 'w-3 h-3' : 'w-4 h-4'} />
   116→            ) : (
   117→              <ChevronRight className={compact ? 'w-3 h-3' : 'w-4 h-4'} />
   118→            )}
   119→          </button>
   120→        ) : (
   121→          <span className={compact ? 'w-4' : 'w-5'} />
   122→        )}
   123→
   124→        {/* Project color indicator */}
   125→        <span
   126→          className={`${compact ? 'w-2 h-2' : 'w-3 h-3'} rounded-full flex-shrink-0`}
   127→          style={{ backgroundColor: project.color }}
   128→        />
   129→
   130→        {/* Icon or folder */}
   131→        {project.icon ? (
   132→          <span className={compact ? 'text-sm' : 'text-base'}>{project.icon}</span>
   133→        ) : hasChildren ? (
   134→          expanded ? (
   135→            <FolderOpen className={`${compact ? 'w-3.5 h-3.5' : 'w-4 h-4'} text-text-light-secondary dark:text-text-dark-secondary`} />
   136→          ) : (
   137→            <Folder className={`${compact ? 'w-3.5 h-3.5' : 'w-4 h-4'} text-text-light-secondary dark:text-text-dark-secondary`} />
   138→          )
   139→        ) : null}
   140→
   141→        {/* Project name */}
   142→        <span className="flex-1 truncate">{project.name}</span>
   143→
   144→        {/* Multi-select checkbox */}
   145→        {selectionMode === 'multi' && (
   146→          <input
   147→            type="checkbox"
   148→            checked={isSelected}
   149→            onChange={() => {}}
   150→            className="w-4 h-4 rounded border-border-light dark:border-border-dark"
   151→          />
   152→        )}
   153→      </button>
   154→
   155→      {/* Render children if expanded */}
   156→      {hasChildren && expanded && (
   157→        <div>
   158→          {childProjects.map((child) => (
   159→            <ProjectNodeWrapper
   160→              key={child.id}
   161→              project={child}
   162→              level={level + 1}
   163→              selectionMode={selectionMode}
   164→              isSelected={false}
   165→              onSelect={onSelect}
   166→              onProjectClick={onProjectClick}
   167→              compact={compact}
   168→            />
   169→          ))}
   170→        </div>
   171→      )}
   172→    </div>
   173→  );
   174→};
   175→
   176→// Wrapper to connect to store for child fetching
   177→const ProjectNodeWrapper: React.FC<Omit<ProjectNodeProps, 'expanded' | 'onToggleExpand' | 'childProjects'> & {
   178→  expandedIds?: Set<string>;
   179→  setExpandedIds?: React.Dispatch<React.SetStateAction<Set<string>>>;
   180→}> = (props) => {
   181→  const getChildProjects = useProjectContextStore((s) => s.getChildProjects);
   182→  const childProjects = getChildProjects(props.project.id);
   183→
   184→  // Use context for expansion state
   185→  const [localExpanded, setLocalExpanded] = useState(false);
   186→
   187→  const handleToggle = useCallback((_id: string) => {
   188→    setLocalExpanded((prev) => !prev);
   189→  }, []);
   190→
   191→  return (
   192→    <ProjectNode
   193→      {...props}
   194→      expanded={localExpanded}
   195→      onToggleExpand={handleToggle}
   196→      childProjects={childProjects}
   197→    />
   198→  );
   199→};
   200→
