     1→/**
     2→ * ProjectPicker Component
     3→ *
     4→ * Reusable project selector for entity creation/edit modals.
     5→ * Allows assigning one or multiple projects to an entity.
     6→ *
     7→ * Used by:
     8→ * - Task modals (TaskModal, QuickAdd)
     9→ * - Note modals (NoteEditor)
    10→ * - Event modals (EventModal)
    11→ * - Link modals (LinkModal)
    12→ * - Time entry modals (TimeEntryModal)
    13→ *
    14→ * Features:
    15→ * - Single or multi-select mode
    16→ * - Inline display with dropdown
    17→ * - Shows selected projects as chips
    18→ * - Defaults to current global context
    19→ */
    20→
    21→import React, { useState, useRef, useEffect, useCallback } from 'react';
    22→import { ChevronDown, X, FolderPlus } from 'lucide-react';
    23→import { useProjectContextStore } from '../stores/useProjectContextStore';
    24→import { ProjectTree } from './ProjectTree';
    25→import type { ProjectContext } from '../types';
    26→
    27→interface ProjectPickerProps {
    28→  /** Currently selected project IDs */
    29→  value: string[];
    30→  /** Callback when selection changes */
    31→  onChange: (projectIds: string[]) => void;
    32→  /** Selection mode: single project or multiple */
    33→  mode?: 'single' | 'multi';
    34→  /** Placeholder text when no projects selected */
    35→  placeholder?: string;
    36→  /** Label for the field */
    37→  label?: string;
    38→  /** Whether the field is required */
    39→  required?: boolean;
    40→  /** Whether to show the label */
    41→  showLabel?: boolean;
    42→  /** Custom class for the container */
    43→  className?: string;
    44→  /** Compact mode for inline use */
    45→  compact?: boolean;
    46→  /** Whether to auto-select current global context if value is empty */
    47→  autoSelectContext?: boolean;
    48→}
    49→
    50→export const ProjectPicker: React.FC<ProjectPickerProps> = ({
    51→  value,
    52→  onChange,
    53→  mode = 'multi',
    54→  placeholder = 'Select project...',
    55→  label = 'Project',
    56→  required = false,
    57→  showLabel = true,
    58→  className = '',
    59→  compact = false,
    60→  autoSelectContext = true,
    61→}) => {
    62→  const [isOpen, setIsOpen] = useState(false);
    63→  const dropdownRef = useRef<HTMLDivElement>(null);
    64→  const triggerRef = useRef<HTMLButtonElement>(null);
    65→
    66→  // Store state
    67→  const projects = useProjectContextStore((s) => s.projects);
    68→  const activeProjectIds = useProjectContextStore((s) => s.activeProjectIds);
    69→
    70→  // Auto-select current context on mount if value is empty
    71→  useEffect(() => {
    72→    if (autoSelectContext && value.length === 0 && activeProjectIds.length > 0) {
    73→      // In single mode, only take the first project
    74→      if (mode === 'single') {
    75→        onChange([activeProjectIds[0]]);
    76→      } else {
    77→        onChange(activeProjectIds);
    78→      }
    79→    }
    80→  }, []); // Only on mount
    81→
    82→  // Get selected project objects
    83→  const selectedProjects = value
    84→    .map((id) => projects.find((p) => p.id === id))
    85→    .filter((p): p is ProjectContext => p !== undefined);
    86→
    87→  // Handle click outside
    88→  useEffect(() => {
    89→    const handleClickOutside = (event: MouseEvent) => {
    90→      if (
    91→        dropdownRef.current &&
    92→        !dropdownRef.current.contains(event.target as Node)
    93→      ) {
    94→        setIsOpen(false);
    95→      }
    96→    };
    97→
    98→    if (isOpen) {
    99→      document.addEventListener('mousedown', handleClickOutside);
   100→    }
   101→
   102→    return () => {
   103→      document.removeEventListener('mousedown', handleClickOutside);
   104→    };
   105→  }, [isOpen]);
   106→
   107→  // Handle keyboard navigation
   108→  const handleKeyDown = useCallback((event: React.KeyboardEvent) => {
   109→    if (event.key === 'Escape') {
   110→      setIsOpen(false);
   111→      triggerRef.current?.focus();
   112→    }
   113→  }, []);
   114→
   115→  // Handle selection from tree
   116→  const handleSelectionChange = useCallback(
   117→    (ids: string[]) => {
   118→      onChange(ids);
   119→      if (mode === 'single') {
   120→        setIsOpen(false);
   121→      }
   122→    },
   123→    [onChange, mode]
   124→  );
   125→
   126→  // Remove a project from selection
   127→  const handleRemoveProject = useCallback(
   128→    (projectId: string, e: React.MouseEvent) => {
   129→      e.stopPropagation();
   130→      onChange(value.filter((id) => id !== projectId));
   131→    },
   132→    [value, onChange]
   133→  );
   134→
   135→  // Clear all selections
   136→  const handleClear = useCallback(
   137→    (e: React.MouseEvent) => {
   138→      e.stopPropagation();
   139→      onChange([]);
   140→    },
   141→    [onChange]
   142→  );
   143→
   144→  return (
   145→    <div ref={dropdownRef} className={`relative ${className}`}>
   146→      {/* Label */}
   147→      {showLabel && (
   148→        <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   149→          {label}
   150→          {required && <span className="text-red-500 ml-1">*</span>}
   151→        </label>
   152→      )}
   153→
   154→      {/* Trigger */}
   155→      <button
   156→        ref={triggerRef}
   157→        type="button"
   158→        onClick={() => setIsOpen(!isOpen)}
   159→        onKeyDown={handleKeyDown}
   160→        className={`
   161→          w-full flex items-center gap-2 text-left
   162→          border border-border-light dark:border-border-dark rounded-lg
   163→          bg-surface-light dark:bg-surface-dark
   164→          transition-all duration-standard ease-smooth
   165→          ${compact ? 'px-2 py-1.5 text-sm' : 'px-3 py-2'}
   166→          ${isOpen
   167→            ? 'ring-2 ring-accent-blue/50 border-accent-blue'
   168→            : 'hover:border-accent-blue/50'
   169→          }
   170→        `}
   171→        aria-haspopup="listbox"
   172→        aria-expanded={isOpen}
   173→      >
   174→        {/* Selected projects display */}
   175→        <div className="flex-1 flex flex-wrap items-center gap-1 min-h-[24px]">
   176→          {selectedProjects.length === 0 ? (
   177→            <span className="text-text-light-tertiary dark:text-text-dark-tertiary">
   178→              {placeholder}
   179→            </span>
   180→          ) : (
   181→            selectedProjects.map((project) => (
   182→              <span
   183→                key={project.id}
   184→                className="
   185→                  inline-flex items-center gap-1 px-2 py-0.5 rounded-full
   186→                  bg-surface-light-elevated dark:bg-neutral-700
   187→                  text-text-light-primary dark:text-text-dark-primary
   188→                  text-xs font-medium
   189→                "
   190→              >
   191→                <span
   192→                  className="w-2 h-2 rounded-full flex-shrink-0"
   193→                  style={{ backgroundColor: project.color }}
   194→                />
   195→                <span className="truncate max-w-[100px]">{project.name}</span>
   196→                {mode === 'multi' && (
   197→                  <button
   198→                    type="button"
   199→                    onClick={(e) => handleRemoveProject(project.id, e)}
   200→                    className="p-0.5 hover:bg-neutral-300 dark:hover:bg-neutral-600 rounded-full transition-colors"
   201→                    aria-label={`Remove ${project.name}`}
   202→                  >
   203→                    <X className="w-3 h-3" />
   204→                  </button>
   205→                )}
   206→              </span>
   207→            ))
   208→          )}
   209→        </div>
