     1→/**
     2→ * Support Modal - Help & Support System
     3→ * Provides issue reporting, help resources, and documentation access
     4→ *
     5→ * Features:
     6→ * - Report Issue tab: Mailto integration with diagnostic report
     7→ * - Get Help tab: Keyboard shortcuts, FAQs, system status
     8→ * - Documentation tab: Version info, external links
     9→ */
    10→
    11→import { useState, useEffect } from 'react';
    12→import { Modal } from './Modal';
    13→import { getDiagnosticReport, formatDiagnosticReport, copyDiagnosticReportToClipboard, downloadDiagnosticReport, type DiagnosticReport } from '../utils/diagnostics';
    14→import { logger } from '../services/logger';
    15→import { Mail, HelpCircle, Book, Copy, Download, ChevronDown, ChevronRight, ExternalLink, Keyboard } from 'lucide-react';
    16→import { BUILD_HASH, formatBuildTimestamp } from '../utils/buildInfo';
    17→import { useShortcutsStore } from '../stores/useShortcutsStore';
