   106→
   107→/**
   108→ * Keyboard Shortcuts Section - displays all registered shortcuts from the shortcuts store
   109→ */
   110→function KeyboardShortcutsSection() {
   111→  const shortcuts = useShortcutsStore((s) => s.getAllShortcuts());
   112→
   113→  // Group shortcuts by context
   114→  const groupedShortcuts = shortcuts.reduce(
   115→    (acc, shortcut) => {
   116→      const context = shortcut.context || 'global';
   117→      if (!acc[context]) acc[context] = [];
   118→      acc[context].push(shortcut);
   119→      return acc;
   120→    },
   121→    {} as Record<string, typeof shortcuts>
   122→  );
   123→
   124→  const contextLabels: Record<string, string> = {
   125→    global: 'Global',
   126→    kanban: 'Tasks/Kanban',
   127→    notes: 'Notes',
   128→    calendar: 'Calendar',
   129→    diagram: 'Diagrams',
   130→    modal: 'Modals',
   131→  };
   132→
   133→  return (
   134→    <div>
   135→      <div className="flex items-center gap-2 mb-3">
   136→        <Keyboard className="w-4 h-4 text-accent-blue" />
   137→        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
   138→          Keyboard Shortcuts
   139→        </h3>
   140→      </div>
   141→
   142→      <div className="space-y-4">
   143→        {Object.entries(groupedShortcuts).map(([context, contextShortcuts]) => (
   144→          <div key={context}>
   145→            <h4 className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   146→              {contextLabels[context] || context}
   147→            </h4>
   148→            <div className="bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark overflow-hidden">
   149→              {contextShortcuts.map((shortcut, index) => (
   150→                <div
   151→                  key={shortcut.id}
   152→                  className={`flex items-center justify-between px-3 py-2 ${
   153→                    index !== contextShortcuts.length - 1
   154→                      ? 'border-b border-border-light dark:border-border-dark'
   155→                      : ''
   156→                  }`}
   157→                >
   158→                  <div className="flex flex-col">
   159→                    <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
   160→                      {shortcut.label}
   161→                    </span>
   162→                    {shortcut.description && (
   163→                      <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   164→                        {shortcut.description}
   165→                      </span>
   166→                    )}
   167→                  </div>
   168→                  <kbd className="px-2 py-1 text-xs font-mono bg-neutral-100 dark:bg-neutral-800 rounded border border-neutral-300 dark:border-neutral-600 text-text-light-primary dark:text-text-dark-primary">
   169→                    {formatShortcut(shortcut.keys)}
   170→                  </kbd>
   171→                </div>
   172→              ))}
   173→            </div>
   174→          </div>
   175→        ))}
   176→
   177→        {shortcuts.length === 0 && (
   178→          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary italic">
   179→            No shortcuts registered yet. Shortcuts will appear here as you use the app.
   180→          </p>
   181→        )}
   182→      </div>
   183→
   184→      {/* Editor shortcuts (hardcoded since they're from Lexical) */}
   185→      <div className="mt-4">
   186→        <h4 className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   187→          Notes Editor
   188→        </h4>
   189→        <div className="bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark overflow-hidden">
   190→          {[
   191→            { keys: ['mod', 'b'], label: 'Bold' },
   192→            { keys: ['mod', 'i'], label: 'Italic' },
   193→            { keys: ['mod', 'u'], label: 'Underline' },
   194→            { keys: ['mod', 'shift', 'e'], label: 'Export notes' },
   195→            { keys: ['/'], label: 'Slash commands menu' },
   196→            { keys: ['[['], label: 'Wiki link autocomplete' },
   197→          ].map((shortcut, index, arr) => (
   198→            <div
   199→              key={shortcut.label}
   200→              className={`flex items-center justify-between px-3 py-2 ${
   201→                index !== arr.length - 1 ? 'border-b border-border-light dark:border-border-dark' : ''
   202→              }`}
   203→            >
   204→              <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
   205→                {shortcut.label}
   206→              </span>
   207→              <kbd className="px-2 py-1 text-xs font-mono bg-neutral-100 dark:bg-neutral-800 rounded border border-neutral-300 dark:border-neutral-600 text-text-light-primary dark:text-text-dark-primary">
   208→                {formatShortcut(shortcut.keys)}
   209→              </kbd>
   210→            </div>
