   217→
   218→export function SupportModal({ isOpen, onClose, initialTab = 'report' }: SupportModalProps) {
   219→  const [activeTab, setActiveTab] = useState<TabType>(initialTab);
   220→  const [issueType, setIssueType] = useState<string>('bug');
   221→  const [description, setDescription] = useState<string>('');
   222→  const [includeDiagnostics, setIncludeDiagnostics] = useState<boolean>(true);
   223→  const [diagnosticReport, setDiagnosticReport] = useState<DiagnosticReport | null>(null);
   224→  const [showDiagnosticPreview, setShowDiagnosticPreview] = useState<boolean>(false);
   225→  const [message, setMessage] = useState<{ type: 'success' | 'error' | 'info'; text: string } | null>(null);
   226→  const [expandedFaq, setExpandedFaq] = useState<number | null>(null);
   227→  const [isGeneratingReport, setIsGeneratingReport] = useState<boolean>(false);
   228→
   229→  // Generate diagnostic report when modal opens or when tab changes to report
   230→  useEffect(() => {
   231→    if (isOpen && activeTab === 'report' && !diagnosticReport) {
   232→      generateDiagnosticReport();
   233→    }
   234→  }, [isOpen, activeTab]);
   235→
   236→  const generateDiagnosticReport = async () => {
   237→    try {
   238→      setIsGeneratingReport(true);
   239→      const report = await getDiagnosticReport();
   240→      setDiagnosticReport(report);
   241→      log.info('Diagnostic report generated for support modal');
   242→    } catch (error) {
   243→      log.error('Failed to generate diagnostic report', { error });
   244→      setMessage({ type: 'error', text: 'Failed to generate diagnostic report' });
   245→    } finally {
   246→      setIsGeneratingReport(false);
   247→    }
   248→  };
   249→
   250→  const handleSendEmail = () => {
   251→    if (!description.trim()) {
   252→      setMessage({ type: 'error', text: 'Please provide a description of the issue' });
   253→      return;
   254→    }
   255→
   256→    try {
   257→      const subject = encodeURIComponent(`[${issueType}] - Neuman Brain Support Request`);
   258→
   259→      let bodyText = `Issue Type: ${issueType}\n`;
   260→      bodyText += `Build: ${BUILD_HASH} (${formatBuildTimestamp()})\n\n`;
   261→      bodyText += `Description:\n${description}\n\n`;
   262→
   263→      if (includeDiagnostics && diagnosticReport) {
   264→        bodyText += '---\nDiagnostic Report:\n\n';
   265→        bodyText += formatDiagnosticReport(diagnosticReport);
   266→      }
   267→
   268→      const body = encodeURIComponent(bodyText);
   269→
   270→      window.open(`mailto:${SUPPORT_EMAIL}?subject=${subject}&body=${body}`);
   271→      setMessage({ type: 'success', text: 'Email client opened. Please send the email to complete your report.' });
   272→      log.info('Mailto link opened for support request', { issueType, includeDiagnostics });
   273→    } catch (error) {
   274→      log.error('Failed to open email client', { error });
   275→      setMessage({ type: 'error', text: 'Failed to open email client. Please copy the diagnostic report manually.' });
   276→    }
   277→  };
   278→
   279→  const handleCopyDiagnosticReport = async () => {
   280→    if (!diagnosticReport) {
   281→      setMessage({ type: 'error', text: 'No diagnostic report available' });
   282→      return;
   283→    }
   284→
   285→    try {
   286→      await copyDiagnosticReportToClipboard(diagnosticReport);
   287→      setMessage({ type: 'success', text: 'Diagnostic report copied to clipboard' });
   288→    } catch (error) {
   289→      log.error('Failed to copy diagnostic report', { error });
   290→      setMessage({ type: 'error', text: 'Failed to copy to clipboard' });
   291→    }
   292→  };
   293→
   294→  const handleDownloadDiagnosticReport = () => {
   295→    if (!diagnosticReport) {
   296→      setMessage({ type: 'error', text: 'No diagnostic report available' });
   297→      return;
   298→    }
   299→
   300→    try {
   301→      downloadDiagnosticReport(diagnosticReport);
   302→      setMessage({ type: 'success', text: 'Diagnostic report downloaded' });
   303→    } catch (error) {
   304→      log.error('Failed to download diagnostic report', { error });
   305→      setMessage({ type: 'error', text: 'Failed to download report' });
   306→    }
   307→  };
   308→
   309→  const toggleFaq = (index: number) => {
   310→    setExpandedFaq(expandedFaq === index ? null : index);
   311→  };
   312→
   313→  // Reset state when modal closes, set initial tab when it opens
   314→  useEffect(() => {
   315→    if (!isOpen) {
   316→      setMessage(null);
   317→      setDescription('');
   318→      setIssueType('bug');
   319→      setIncludeDiagnostics(true);
   320→      setExpandedFaq(null);
   321→    } else {
   322→      // Set the active tab to initialTab when modal opens
   323→      setActiveTab(initialTab);
   324→    }
   325→  }, [isOpen, initialTab]);
   326→
   327→  // Auto-dismiss success messages
   328→  useEffect(() => {
   329→    if (message?.type === 'success') {
   330→      const timer = setTimeout(() => setMessage(null), 5000);
   331→      return () => clearTimeout(timer);
   332→    }
   333→  }, [message]);
   334→
   335→  return (
   336→    <Modal isOpen={isOpen} onClose={onClose} title="Help & Support" maxWidth="2xl">
   337→      {/* Tabs */}
   338→      <div className="flex gap-2 mb-6 border-b border-border-light dark:border-border-dark">
   339→        <button
   340→          onClick={() => setActiveTab('report')}
   341→          className={`px-4 py-2 font-medium transition-colors ${
   342→            activeTab === 'report'
   343→              ? 'text-accent-magenta border-b-2 border-accent-magenta'
   344→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   345→          }`}
   346→        >
   347→          <div className="flex items-center gap-2">
   348→            <Mail className="w-4 h-4" />
   349→            <span>Report Issue</span>
   350→          </div>
   351→        </button>
   352→
   353→        <button
   354→          onClick={() => setActiveTab('help')}
   355→          className={`px-4 py-2 font-medium transition-colors ${
   356→            activeTab === 'help'
   357→              ? 'text-accent-cyan border-b-2 border-accent-cyan'
   358→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   359→          }`}
   360→        >
   361→          <div className="flex items-center gap-2">
   362→            <HelpCircle className="w-4 h-4" />
   363→            <span>Get Help</span>
   364→          </div>
   365→        </button>
   366→
   367→        <button
   368→          onClick={() => setActiveTab('docs')}
   369→          className={`px-4 py-2 font-medium transition-colors ${
   370→            activeTab === 'docs'
   371→              ? 'text-accent-blue border-b-2 border-accent-blue'
   372→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   373→          }`}
   374→        >
   375→          <div className="flex items-center gap-2">
   376→            <Book className="w-4 h-4" />
   377→            <span>Documentation</span>
   378→          </div>
   379→        </button>
   380→      </div>
   381→
   382→      {/* Message Banner */}
   383→      {message && (
   384→        <div
   385→          className={`mb-4 p-3 rounded-lg text-sm ${
   386→            message.type === 'success'
   387→              ? 'bg-status-success-bg dark:bg-status-success-bg-dark text-status-success-text dark:text-status-success-text-dark border border-status-success-border dark:border-status-success-border-dark'
   388→              : message.type === 'error'
   389→              ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark border border-status-error-border dark:border-status-error-border-dark'
   390→              : 'bg-status-info-bg dark:bg-status-info-bg-dark text-status-info-text dark:text-status-info-text-dark border border-status-info-border dark:border-status-info-border-dark'
   391→          }`}
   392→        >
   393→          {message.text}
   394→        </div>
   395→      )}
   396→
   397→      {/* Tab Content */}
   398→      {activeTab === 'report' && (
   399→        <div className="space-y-4">
   400→          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   401→            Experiencing a problem? Send us a diagnostic report to help us troubleshoot.
   402→          </p>
   403→
   404→          {/* Issue Type */}
   405→          <div>
   406→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   407→              Issue Type
   408→            </label>
   409→            <select
   410→              value={issueType}
   411→              onChange={(e) => setIssueType(e.target.value)}
   412→              className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
   413→            >
   414→              <option value="bug">Bug Report</option>
   415→              <option value="feature">Feature Request</option>
   416→              <option value="performance">Performance Issue</option>
   417→              <option value="data-loss">Data Loss/Corruption</option>
   418→              <option value="ui-feedback">UI/UX Feedback</option>
   419→              <option value="other">Other</option>
   420→            </select>
   421→          </div>
   422→
   423→          {/* Description */}
   424→          <div>
   425→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   426→              Description <span className="text-status-error">*</span>
   427→            </label>
   428→            <textarea
   429→              value={description}
   430→              onChange={(e) => setDescription(e.target.value)}
   431→              placeholder="Please describe the issue you're experiencing..."
   432→              rows={6}
   433→              className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta resize-none"
   434→            />
   435→          </div>
   436→
   437→          {/* Include Diagnostic Report */}
   438→          <div className="flex items-start gap-3">
   439→            <input
   440→              type="checkbox"
   441→              id="include-diagnostics"
   442→              checked={includeDiagnostics}
   443→              onChange={(e) => setIncludeDiagnostics(e.target.checked)}
   444→              className="mt-1 w-4 h-4 rounded border-border-light dark:border-border-dark"
   445→            />
   446→            <div className="flex-1">
   447→              <label htmlFor="include-diagnostics" className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary cursor-pointer">
   448→                Include diagnostic report (recommended)
   449→              </label>
   450→              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   451→                Provides system info, storage stats, and error logs to help us troubleshoot. No personal data included.
   452→              </p>
   453→            </div>
   454→          </div>
   455→
   456→          {/* Diagnostic Preview */}
   457→          {includeDiagnostics && diagnosticReport && (
   458→            <div>
   459→              <button
   460→                onClick={() => setShowDiagnosticPreview(!showDiagnosticPreview)}
   461→                className="flex items-center gap-2 text-sm font-medium text-accent-magenta hover:text-accent-magenta-hover transition-colors"
   462→              >
   463→                {showDiagnosticPreview ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
   464→                <span>Preview Diagnostic Report</span>
   465→              </button>
   466→
   467→              {showDiagnosticPreview && (
   468→                <div className="mt-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark">
   469→                  <pre className="text-xs font-mono text-text-light-secondary dark:text-text-dark-secondary whitespace-pre-wrap overflow-auto max-h-64">
   470→                    {formatDiagnosticReport(diagnosticReport)}
   471→                  </pre>
   472→                </div>
   473→              )}
   474→            </div>
   475→          )}
   476→
   477→          {/* Actions */}
   478→          <div className="flex gap-3 pt-4 border-t border-border-light dark:border-border-dark">
   479→            <button
   480→              onClick={handleSendEmail}
   481→              disabled={isGeneratingReport}
   482→              className="flex-1 px-4 py-2 bg-accent-magenta hover:bg-accent-magenta-hover text-white rounded-lg font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
   483→            >
   484→              <div className="flex items-center justify-center gap-2">
   485→                <Mail className="w-4 h-4" />
   486→                <span>Open Email Client</span>
   487→              </div>
   488→            </button>
   489→
   490→            <button
