              onClick={handleSendEmail}
              disabled={isGeneratingReport}
              className="flex-1 px-4 py-2 bg-accent-magenta hover:bg-accent-magenta-hover text-white rounded-lg font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
