  // Handle keyboard navigation
  const handleKeyDown = useCallback((event: React.KeyboardEvent) => {
    if (event.key === 'Escape') {
      setIsOpen(false);
      triggerRef.current?.focus();
    }
  }, []);

  // Handle selection from tree
  const handleSelectionChange = useCallback(
    (ids: string[]) => {
      onChange(ids);
      if (mode === 'single') {
        setIsOpen(false);
      }
    },
    [onChange, mode]
  );

  // Remove a project from selection
  const handleRemoveProject = useCallback(
    (projectId: string, e: React.MouseEvent) => {
      e.stopPropagation();
      onChange(value.filter((id) => id !== projectId));
    },
    [value, onChange]
  );

  // Clear all selections
  const handleClear = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation();
      onChange([]);
    },
    [onChange]
  );

  return (
    <div ref={dropdownRef} className={`relative ${className}`}>
      {/* Label */}
      {showLabel && (
        <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
          {label}
          {required && <span className="text-accent-red ml-1">*</span>}
        </label>
      )}

      {/* Trigger */}
      <button
        ref={triggerRef}
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        onKeyDown={handleKeyDown}
        className={`
          w-full flex items-center gap-2 text-left
          border border-border-light dark:border-border-dark rounded-lg
          bg-surface-light dark:bg-surface-dark
          transition-all duration-standard ease-smooth
          ${compact ? 'px-2 py-1.5 text-sm' : 'px-3 py-2'}
          ${isOpen
            ? 'ring-2 ring-accent-blue/50 border-accent-blue'
            : 'hover:border-accent-blue/50'
          }
        `}
        aria-haspopup="listbox"
        aria-expanded={isOpen}
      >
        {/* Selected projects display */}
        <div className="flex-1 flex flex-wrap items-center gap-1 min-h-[24px]">
          {selectedProjects.length === 0 ? (
            <span className="text-text-light-tertiary dark:text-text-dark-tertiary">
              {placeholder}
            </span>
          ) : (
            selectedProjects.map((project) => (
              <span
                key={project.id}
                className="
                  inline-flex items-center gap-1 px-2 py-0.5 rounded-full
                  bg-surface-light-elevated dark:bg-neutral-700
                  text-text-light-primary dark:text-text-dark-primary
                  text-xs font-medium
                "
              >
                <span
                  className="w-2 h-2 rounded-full flex-shrink-0"
                  style={{ backgroundColor: project.color }}
                />
                <span className="truncate max-w-[100px]">{project.name}</span>
                {mode === 'multi' && (
                  <button
                    type="button"
                    onClick={(e) => handleRemoveProject(project.id, e)}
                    className="p-0.5 hover:bg-neutral-300 dark:hover:bg-neutral-600 rounded-full transition-colors"
                    aria-label={`Remove ${project.name}`}
                  >
                    <X className="w-3 h-3" />
                  </button>
                )}
              </span>
            ))
          )}
        </div>

        {/* Clear button */}
        {selectedProjects.length > 0 && mode === 'multi' && (
          <button
            type="button"
            onClick={handleClear}
            className="p-1 text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            aria-label="Clear all"
          >
            <X className="w-4 h-4" />
          </button>
        )}

        {/* Chevron */}
        <ChevronDown
          className={`w-4 h-4 flex-shrink-0 text-text-light-secondary dark:text-text-dark-secondary transition-transform duration-standard ${
            isOpen ? 'rotate-180' : ''
          }`}
        />
      </button>

      {/* Dropdown */}
      {isOpen && (
        <div
          className="
            absolute top-full left-0 right-0 mt-1
            max-h-[300px] overflow-hidden
            bg-surface-light dark:bg-surface-dark
            border border-border-light dark:border-border-dark
            rounded-lg shadow-xl
            z-50
            animate-fadeIn
          "
          role="listbox"
          onKeyDown={handleKeyDown}
        >
          {projects.length === 0 ? (
            <div className="p-4 text-center">
              <FolderPlus className="w-8 h-8 mx-auto mb-2 text-text-light-tertiary dark:text-text-dark-tertiary" />
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                No projects yet
              </p>
              <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
                Create projects in Settings → Projects
              </p>
            </div>
          ) : (
            <div className="max-h-[300px] overflow-y-auto">
              <ProjectTree
                selectionMode={mode}
                selectedIds={value}
                onSelectionChange={handleSelectionChange}
                showAllOption={false}
                compact={true}
              />
            </div>
          )}
        </div>
      )}
    </div>
  );
};

/**
 * ProjectPicker Component
 *
 * Reusable project selector for entity creation/edit modals.
 * Allows assigning one or multiple projects to an entity.
 *
 * Used by:
 * - Task modals (TaskModal, QuickAdd)
 * - Note modals (NoteEditor)
 * - Event modals (EventModal)
 * - Link modals (LinkModal)
 * - Time entry modals (TimeEntryModal)
 *
 * Features:
 * - Single or multi-select mode
 * - Inline display with dropdown
 * - Shows selected projects as chips
 * - Defaults to current global context
 */

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ChevronDown, X, FolderPlus } from 'lucide-react';
import { useProjectContextStore } from '../stores/useProjectContextStore';
import { ProjectTree } from './ProjectTree';
import type { ProjectContext } from '../types';

interface ProjectPickerProps {
  /** Currently selected project IDs */
  value: string[];
  /** Callback when selection changes */
  onChange: (projectIds: string[]) => void;
  /** Selection mode: single project or multiple */
  mode?: 'single' | 'multi';
  /** Placeholder text when no projects selected */
  placeholder?: string;
  /** Label for the field */
  label?: string;
  /** Whether the field is required */
  required?: boolean;
  /** Whether to show the label */
  showLabel?: boolean;
  /** Custom class for the container */
  className?: string;
  /** Compact mode for inline use */
  compact?: boolean;
  /** Whether to auto-select current global context if value is empty */
  autoSelectContext?: boolean;
}

export const ProjectPicker: React.FC<ProjectPickerProps> = ({
  value,
  onChange,
  mode = 'multi',
  placeholder = 'Select project...',
  label = 'Project',
  required = false,
  showLabel = true,
  className = '',
  compact = false,
  autoSelectContext = true,
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLButtonElement>(null);

  // Store state
  const projects = useProjectContextStore((s) => s.projects);
  const activeProjectIds = useProjectContextStore((s) => s.activeProjectIds);

  // Auto-select current context on mount if value is empty
  useEffect(() => {
    if (autoSelectContext && value.length === 0 && activeProjectIds.length > 0) {
      // In single mode, only take the first project
      if (mode === 'single') {
        onChange([activeProjectIds[0]]);
      } else {
        onChange(activeProjectIds);
      }
    }
  }, []); // Only on mount

  // Get selected project objects
  const selectedProjects = value
    .map((id) => projects.find((p) => p.id === id))
    .filter((p): p is ProjectContext => p !== undefined);

  // Handle click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node)
      ) {
        setIsOpen(false);
      }
    };

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [isOpen]);

  // Handle keyboard navigation
  const handleKeyDown = useCallback((event: React.KeyboardEvent) => {
    if (event.key === 'Escape') {
      setIsOpen(false);
      triggerRef.current?.focus();
    }
  }, []);

  // Handle selection from tree
  const handleSelectionChange = useCallback(
    (ids: string[]) => {
      onChange(ids);
      if (mode === 'single') {
        setIsOpen(false);
      }
    },
    [onChange, mode]
  );

  // Remove a project from selection
  const handleRemoveProject = useCallback(
    (projectId: string, e: React.MouseEvent) => {
      e.stopPropagation();
      onChange(value.filter((id) => id !== projectId));
    },
    [value, onChange]
  );

  // Clear all selections
  const handleClear = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation();
      onChange([]);
    },
    [onChange]
  );

  return (
    <div ref={dropdownRef} className={`relative ${className}`}>
      {/* Label */}
      {showLabel && (
        <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
          {label}
          {required && <span className="text-accent-red ml-1">*</span>}
        </label>
      )}

      {/* Trigger */}
      <button
        ref={triggerRef}
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        onKeyDown={handleKeyDown}
        className={`
          w-full flex items-center gap-2 text-left
          border border-border-light dark:border-border-dark rounded-lg
          bg-surface-light dark:bg-surface-dark
          transition-all duration-standard ease-smooth
          ${compact ? 'px-2 py-1.5 text-sm' : 'px-3 py-2'}
          ${isOpen
            ? 'ring-2 ring-accent-blue/50 border-accent-blue'
            : 'hover:border-accent-blue/50'
          }
        `}
        aria-haspopup="listbox"
        aria-expanded={isOpen}
      >
        {/* Selected projects display */}
        <div className="flex-1 flex flex-wrap items-center gap-1 min-h-[24px]">
          {selectedProjects.length === 0 ? (
            <span className="text-text-light-tertiary dark:text-text-dark-tertiary">
              {placeholder}
            </span>
          ) : (
            selectedProjects.map((project) => (
              <span
                key={project.id}
                className="
                  inline-flex items-center gap-1 px-2 py-0.5 rounded-full
                  bg-surface-light-elevated dark:bg-surface-dark-elevated
                  text-text-light-primary dark:text-text-dark-primary
                  text-xs font-medium
                "
              >
                <span
                  className="w-2 h-2 rounded-full flex-shrink-0"
                  style={{ backgroundColor: project.color }}
                />
                <span className="truncate max-w-[100px]">{project.name}</span>
                {mode === 'multi' && (
                  <button
                    type="button"
                    onClick={(e) => handleRemoveProject(project.id, e)}
                    className="p-0.5 hover:bg-neutral-300 dark:hover:bg-neutral-600 rounded-full transition-colors"
                    aria-label={`Remove ${project.name}`}
                  >
                    <X className="w-3 h-3" />
                  </button>
                )}
              </span>
            ))
          )}
        </div>

        {/* Clear button */}
        {selectedProjects.length > 0 && mode === 'multi' && (
          <button
            type="button"
            onClick={handleClear}
            className="p-1 text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            aria-label="Clear all"
          >
            <X className="w-4 h-4" />
          </button>
        )}

        {/* Chevron */}
        <ChevronDown
          className={`w-4 h-4 flex-shrink-0 text-text-light-secondary dark:text-text-dark-secondary transition-transform duration-standard ${
            isOpen ? 'rotate-180' : ''
          }`}
        />
      </button>

      {/* Dropdown */}
      {isOpen && (
        <div
          className="
            absolute top-full left-0 right-0 mt-1
            max-h-[300px] overflow-hidden
            bg-surface-light dark:bg-surface-dark
            border border-border-light dark:border-border-dark
            rounded-lg shadow-xl
            z-50
            animate-fadeIn
          "
          role="listbox"
          onKeyDown={handleKeyDown}
        >
          {projects.length === 0 ? (
            <div className="p-4 text-center">
              <FolderPlus className="w-8 h-8 mx-auto mb-2 text-text-light-tertiary dark:text-text-dark-tertiary" />
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                No projects yet
              </p>
              <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
                Create projects in Settings → Projects
              </p>
            </div>
          ) : (
            <div className="max-h-[300px] overflow-y-auto">
              <ProjectTree
                selectionMode={mode}
                selectedIds={value}
                onSelectionChange={handleSelectionChange}
                showAllOption={false}
                compact={true}
              />
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import { useState, useEffect } from 'react';
import { Plus, Pencil, Trash2, FolderOpen, Archive } from 'lucide-react';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
import type { TimeTrackingProject } from '../types';

// Predefined color palette for projects
const PROJECT_COLORS = [
  '#FF6B6B', // Red
  '#4ECDC4', // Cyan
  '#45B7D1', // Blue
  '#FFA07A', // Orange
  '#98D8C8', // Mint
  '#F7DC6F', // Yellow
  '#BB8FCE', // Purple
  '#85C1E2', // Light Blue
  '#52B788', // Green
  '#F8B500', // Gold
];

interface ProjectFormData {
  name: string;
  color: string;
  clientName?: string;
  hourlyRate?: number;
  active: boolean;
}

/**
 * ProjectManager Component
 * CRUD interface for managing time tracking projects
 */
export function ProjectManager() {
  const {
    projects,
    loadProjects,
    addProject,
    updateProject,
    deleteProject,
  } = useTimeTrackingStore();

  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<ProjectFormData>({
    name: '',
    color: PROJECT_COLORS[0],
    clientName: '',
    hourlyRate: undefined,
    active: true,
  });
  const [formError, setFormError] = useState('');

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        await loadProjects();
      } catch (error) {
        console.error('Failed to load projects:', error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [loadProjects]);

  const handleOpenForm = (project?: TimeTrackingProject) => {
    if (project) {
      setEditingId(project.id);
      setFormData({
        name: project.name,
        color: project.color,
        clientName: project.clientName || '',
        hourlyRate: project.hourlyRate,
        active: project.active,
      });
    } else {
      setEditingId(null);
      setFormData({
        name: '',
        color: PROJECT_COLORS[Math.floor(Math.random() * PROJECT_COLORS.length)],
        clientName: '',
        hourlyRate: undefined,
        active: true,
      });
    }
    setFormError('');
    setShowForm(true);
  };

  const handleCloseForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormError('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError('');

    // Validation
    if (!formData.name.trim()) {
      setFormError('Project name is required');
      return;
    }

    try {
      if (editingId) {
        await updateProject(editingId, formData);
      } else {
        await addProject({ ...formData, archived: false });
      }

      handleCloseForm();
      await loadProjects(); // Refresh list
    } catch (error) {
      console.error('Failed to save project:', error);
      setFormError('Failed to save project. Please try again.');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this project? This action cannot be undone.')) {
      return;
    }

    setDeletingId(id);
    try {
      await deleteProject(id);
      await loadProjects(); // Refresh list
    } catch (error) {
      console.error('Failed to delete project:', error);
      alert('Failed to delete project. Please try again.');
    } finally {
      setDeletingId(null);
    }
  };

  const handleToggleActive = async (project: TimeTrackingProject) => {
    try {
      await updateProject(project.id, { active: !project.active });
      await loadProjects(); // Refresh list
    } catch (error) {
      console.error('Failed to update project:', error);
      alert('Failed to update project status. Please try again.');
    }
  };

  const activeProjects = projects.filter(p => p.active && !p.archived);
  const archivedProjects = projects.filter(p => !p.active || p.archived);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="text-text-light-secondary dark:text-text-dark-secondary">
          Loading projects...
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">
            Projects
          </h2>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
            Organize your time entries by project
          </p>
        </div>
        <button
          onClick={() => handleOpenForm()}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white dark:text-dark-background bg-accent-magenta dark:bg-accent-cyan rounded-buttonhover:opacity-90 transition-opacity"
        >
          <Plus className="w-4 h-4" />
          New Project
        </button>
      </div>

      {/* Project Form */}
      {showForm && (
        <div className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark p-6">
          <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
            {editingId ? 'Edit Project' : 'New Project'}
          </h3>

          <form onSubmit={handleSubmit} className="space-y-4">
            {formError && (
              <div className="px-4 py-3 bg-status-error/10 border border-status-error/20 rounded-buttontext-status-error text-sm">
                {formError}
              </div>
            )}

            {/* Project Name */}
            <div>
              <label
                htmlFor="projectName"
                className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
              >
                Project Name *
              </label>
              <input
                id="projectName"
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
                placeholder="e.g., Neuman Brain, Client Work"
                autoFocus
              />
            </div>

            {/* Project Color */}
            <div>
              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                Color
              </label>
              <div className="grid grid-cols-10 gap-2">
                {PROJECT_COLORS.map(color => (
                  <button
                    key={color}
                    type="button"
                    onClick={() => setFormData({ ...formData, color })}
                    className={`w-8 h-8 rounded-full transition-transform hover:scale-110 ${
                      formData.color === color ? 'ring-2 ring-offset-2 ring-accent-magenta dark:ring-accent-cyan scale-110' : ''
                    }`}
                    style={{ backgroundColor: color }}
                    title={color}
                  />
                ))}
              </div>
            </div>

            {/* Client Name */}
            <div>
              <label
                htmlFor="projectClientName"
                className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
              >
                Client Name <span className="text-text-light-tertiary dark:text-text-dark-tertiary font-normal">(optional)</span>
              </label>
              <input
                id="projectClientName"
                type="text"
                value={formData.clientName}
                onChange={(e) => setFormData({ ...formData, clientName: e.target.value })}
                className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
                placeholder="e.g., Acme Corp, John Doe"
              />
            </div>

            {/* Hourly Rate */}
            <div>
              <label
                htmlFor="projectHourlyRate"
                className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
              >
                Default Hourly Rate <span className="text-text-light-tertiary dark:text-text-dark-tertiary font-normal">(optional)</span>
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-text-light-secondary dark:text-text-dark-secondary text-sm">
                  $
                </span>
                <input
                  id="projectHourlyRate"
                  type="number"
                  min="0"
                  step="0.01"
                  value={formData.hourlyRate || ''}
                  onChange={(e) => setFormData({ ...formData, hourlyRate: e.target.value ? parseFloat(e.target.value) : undefined })}
                  className="w-full pl-7 pr-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
                  placeholder="0.00"
                />
              </div>
              <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
                Used to calculate billable amounts for time entries
              </p>
            </div>

            {/* Active Status */}
            <div className="flex items-center gap-3">
              <input
                id="projectActive"
                type="checkbox"
                checked={formData.active}
                onChange={(e) => setFormData({ ...formData, active: e.target.checked })}
                className="w-4 h-4 text-accent-magenta dark:text-accent-cyan bg-surface-light-elevated dark:bg-surface-dark-elevated border-border-light dark:border-border-dark rounded-buttonfocus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan"
              />
              <label
                htmlFor="projectActive"
                className="text-sm text-text-light-primary dark:text-text-dark-primary"
              >
                Active (show in project selector)
              </label>
            </div>

            {/* Form Actions */}
            <div className="flex items-center justify-end gap-3 pt-2">
              <button
                type="button"
                onClick={handleCloseForm}
                className="px-4 py-2 text-sm font-medium text-text-light-primary dark:text-text-dark-primary bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonhover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="px-4 py-2 text-sm font-medium text-white dark:text-dark-background bg-accent-magenta dark:bg-accent-cyan rounded-buttonhover:opacity-90 transition-opacity"
              >
                {editingId ? 'Update Project' : 'Create Project'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Active Projects List */}
      <div>
        <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-3 flex items-center gap-2">
