// Predefined color palette for projects
const PROJECT_COLORS = [
  '#FF6B6B', // Red
  '#4ECDC4', // Cyan
  '#45B7D1', // Blue
  '#FFA07A', // Orange
  '#98D8C8', // Mint
  '#F7DC6F', // Yellow
  '#BB8FCE', // Purple
  '#85C1E2', // Light Blue
  '#52B788', // Green
  '#F8B500', // Gold
];

interface ProjectFormData {
  name: string;
  color: string;
  clientName?: string;
  hourlyRate?: number;
  active: boolean;
}

/**
 * ProjectManager Component
 * CRUD interface for managing time tracking projects
 */
export function ProjectManager() {
